<>
  <meta charSet="utf-8" />
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <title>Messages — UKM Students off School Rented System</title>
  <style
    dangerouslySetInnerHTML={{
      __html:
        '\n  :root{\n    --bg:#f6f8fb;\n    --card-bg: rgba(255,255,255,0.92);\n    --accent:#1e88ff; --accent-2:#0b3d91;\n    --ink:#071028; --muted:#6a7480;\n    --radius:14px; --shadow:0 18px 40px rgba(7,12,25,0.12);\n    --ease:cubic-bezier(.2,.9,.2,1);\n    --success:#17c964; --danger:#ff6257;\n  }\n  html,body{height:100%;margin:0;font-family:-apple-system,"SF Pro Text","Segoe UI",Roboto,Arial;color:var(--ink);background:linear-gradient(180deg,#eef3fb,#fff);-webkit-font-smoothing:antialiased}\n  .page{min-height:100vh;padding:18px;box-sizing:border-box;opacity:0;transform:translateY(8px);animation:pageIn 420ms var(--ease) forwards}\n  @keyframes pageIn{to{opacity:1;transform:none}}\n\n  header.appbar{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:12px 16px;border-radius:calc(var(--radius)+6px);background:linear-gradient(180deg,rgba(255,255,255,0.76),rgba(255,255,255,0.6));box-shadow:var(--shadow);backdrop-filter:blur(8px)}\n  .brand{display:flex;gap:12px;align-items:center}\n  .logo{width:52px;height:44px;border-radius:10px;background:linear-gradient(135deg,var(--accent),var(--accent-2));display:grid;place-items:center;color:white;font-weight:700}\n  nav.actions{display:flex;gap:8px;align-items:center}\n  .btn{padding:8px 12px;border-radius:10px;border:0;cursor:pointer}\n  .btn-primary{background:linear-gradient(90deg,var(--accent),var(--accent-2));color:#fff}\n  .btn-ghost{background:transparent;border:1px solid rgba(10,16,28,0.06);color:var(--accent-2)}\n  .tiny{font-size:13px;color:var(--muted)}\n\n  .layout{display:grid;grid-template-columns:320px 1fr;gap:18px;margin-top:14px;height:calc(100vh - 140px)}\n  @media(max-width:1000px){ .layout{grid-template-columns:1fr;height:auto} }\n\n  .panel{background:var(--card-bg);border-radius:12px;padding:12px;box-shadow:0 8px 26px rgba(8,12,24,0.06);display:flex;flex-direction:column;gap:8px}\n  .conversations{overflow:auto;flex:1;display:flex;flex-direction:column;gap:8px;padding-right:4px}\n  .conv-item{display:flex;gap:10px;align-items:center;padding:10px;border-radius:10px;cursor:pointer;transition:background .18s,var(--ease)}\n  .conv-item:hover{background:rgba(11,61,145,0.03)}\n  .conv-item.active{background:linear-gradient(90deg,rgba(30,136,255,0.06),rgba(30,136,255,0.02));border-left:4px solid var(--accent-2)}\n  .avatar{width:48px;height:48px;border-radius:10px;background:linear-gradient(135deg,var(--accent),var(--accent-2));display:grid;place-items:center;color:white;font-weight:800}\n  .conv-body{flex:1;display:flex;flex-direction:column}\n  .conv-top{display:flex;justify-content:space-between;align-items:center}\n  .conv-title{font-weight:700}\n  .conv-sub{font-size:13px;color:var(--muted)}\n\n  /* chat area */\n  .chat-area{display:flex;flex-direction:column;gap:12px;height:100%;min-height:320px}\n  .chat-header{display:flex;justify-content:space-between;align-items:center;padding:8px;border-bottom:1px solid rgba(10,16,28,0.04)}\n  .messages{flex:1;overflow:auto;padding:12px;display:flex;flex-direction:column;gap:10px}\n  .msg{max-width:72%;padding:10px;border-radius:12px;background:linear-gradient(180deg,#fff,#fbfdff);box-shadow:0 6px 20px rgba(8,12,24,0.04)}\n  .msg.me{margin-left:auto;background:linear-gradient(90deg,var(--accent),var(--accent-2));color:#fff}\n  .msg .meta{font-size:12px;color:var(--muted);margin-bottom:6px}\n  .msg .file{margin-top:8px;padding:8px;border-radius:8px;background:rgba(255,255,255,0.95);border:1px solid rgba(10,16,28,0.03);font-size:13px}\n\n  .composer{display:flex;gap:8px;padding:10px;border-top:1px solid rgba(10,16,28,0.04);align-items:center}\n  .input{flex:1;padding:10px;border-radius:10px;border:1px solid rgba(10,16,28,0.06);background:white}\n  .attach{padding:8px;border-radius:8px;border:1px dashed rgba(10,16,28,0.06);cursor:pointer}\n  .small{font-size:13px;color:var(--muted)}\n\n  /* file preview in composer */\n  .compose-files{display:flex;gap:8px;align-items:center;margin-top:8px;flex-wrap:wrap}\n  .compose-preview{width:80px;height:60px;border-radius:8px;background:#fff;border:1px solid rgba(10,16,28,0.04);display:grid;place-items:center;overflow:hidden}\n  .compose-preview img{width:100%;height:100%;object-fit:cover}\n\n  /* modal */\n  .modal-backdrop{position:fixed;inset:0;background:rgba(6,10,20,0.36);display:none;align-items:center;justify-content:center;z-index:90}\n  .modal{width:min(520px,94vw);background:white;border-radius:12px;padding:16px;box-shadow:0 30px 80px rgba(2,6,23,0.28)}\n\n  /* toast */\n  .__toast{position:fixed;left:50%;bottom:24px;transform:translateX(-50%);z-index:100;padding:8px 14px;border-radius:10px;color:#fff;box-shadow:0 10px 30px rgba(14,54,120,0.12)}\n'
    }}
  />
  <div className="page" role="document">
    <header className="appbar" role="banner">
      <div className="brand">
        <div className="logo">UKM</div>
        <div>
          <div style={{ fontWeight: 700 }}>
            UKM Students off School Rented System
          </div>
          <div className="tiny">Messages</div>
        </div>
      </div>
      <nav className="actions" role="navigation">
        <a href="index.html" className="btn btn-ghost">
          Home
        </a>
        <a href="host-dashboard.html" className="btn btn-ghost">
          Dashboard
        </a>
        <a href="applications.html" className="btn btn-ghost">
          Applications
        </a>
        <a href="login.html" className="btn btn-ghost">
          Log in
        </a>
      </nav>
    </header>
    <main className="layout" role="main">
      {/* left: conversations */}
      <section className="panel" aria-label="Conversations">
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center"
          }}
        >
          <div style={{ fontWeight: 700 }}>Inbox</div>
          <div style={{ display: "flex", gap: 8 }}>
            <input
              id="convSearch"
              type="search"
              placeholder="Search"
              style={{
                padding: 8,
                borderRadius: 8,
                border: "1px solid rgba(10,16,28,0.06)"
              }}
            />
            <button id="newConvBtn" className="btn btn-primary">
              New
            </button>
          </div>
        </div>
        <div
          className="conversations"
          id="conversations"
          tabIndex={0}
          aria-live="polite"
        >
          {/* dynamic */}
        </div>
        <div style={{ marginTop: 8, textAlign: "center" }} className="tiny">
          Tip: Guests cannot send messages.
        </div>
      </section>
      {/* right: chat */}
      <section className="panel chat-area" aria-label="Chat area">
        <div className="chat-header">
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <div id="chatAvatar" className="avatar">
              AB
            </div>
            <div>
              <div id="chatTitle" style={{ fontWeight: 700 }}>
                Select a conversation
              </div>
              <div id="chatSub" className="tiny">
                —
              </div>
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <button id="muteBtn" className="btn btn-ghost">
              Mute
            </button>
            <button id="closeChat" className="btn btn-ghost">
              Close
            </button>
          </div>
        </div>
        <div className="messages" id="messages" aria-live="polite">
          <div className="tiny" style={{ color: "var(--muted)" }}>
            No conversation selected.
          </div>
        </div>
        <div style={{ padding: 8 }}>
          <div
            id="composeWrapper"
            style={{ display: "flex", flexDirection: "column" }}
          >
            <div className="composer">
              <input
                id="messageInput"
                className="input"
                type="text"
                placeholder="Write a message..."
                aria-label="Message input"
              />
              <label
                htmlFor="attachFile"
                className="attach"
                title="Attach file"
              >
                📎
              </label>
              <input
                id="attachFile"
                type="file"
                accept="image/*,application/pdf"
                style={{ display: "none" }}
              />
              <button id="sendBtn" className="btn btn-primary">
                Send
              </button>
            </div>
            <div className="compose-files" id="composeFiles" />
          </div>
        </div>
      </section>
    </main>
    <footer
      style={{
        textAlign: "center",
        color: "var(--muted)",
        fontSize: 13,
        padding: "12px 0",
        marginTop: 12
      }}
    >
      © 2025 UKM Students off School Rented System
    </footer>
  </div>
  {/* Sign-in modal */}
  <div
    className="modal-backdrop"
    id="modalBackdrop"
    role="dialog"
    aria-modal="true"
    aria-hidden="true"
  >
    <div className="modal">
      <h3>Sign in required</h3>
      <p>You must sign in to send messages. Please sign in or register.</p>
      <div
        style={{
          display: "flex",
          gap: 8,
          justifyContent: "flex-end",
          marginTop: 12
        }}
      >
        <a href="login.html" className="btn btn-ghost">
          Sign in
        </a>
        <a href="register.html" className="btn btn-primary">
          Register
        </a>
      </div>
    </div>
  </div>
</>
